import{_ as t,o as r,c as a,a1 as i}from"./chunks/framework.BX4nIuL2.js";const m=JSON.parse('{"title":"FDM 3D printing background","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/3_3dprinter/2.FDM3Dprintingbackground.md","filePath":"courses/fab-course/doc/3_3dprinter/2.FDM3Dprintingbackground.md"}'),o={name:"courses/fab-course/doc/3_3dprinter/2.FDM3Dprintingbackground.md"};function n(s,e,p,l,c,d){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="fdm-3d-printing-background" tabindex="-1">FDM 3D printing background <a class="header-anchor" href="#fdm-3d-printing-background" aria-label="Permalink to &quot;FDM 3D printing background&quot;">​</a></h1><h2 id="_1-basic-knowledge" tabindex="-1">1.Basic knowledge <a class="header-anchor" href="#_1-basic-knowledge" aria-label="Permalink to &quot;1.Basic knowledge&quot;">​</a></h2><p><em><strong>FDM(Fused deposition modeling)</strong></em> ,also called FFF(Fused filament fabrication or filament freeform fabrication). It was developed by <a href="https://en.wikipedia.org/wiki/S._Scott_Crump" target="_blank" rel="noreferrer">S.cott Crump</a> , co-found of <a href="https://www.stratasys.com/" target="_blank" rel="noreferrer">Stratasys</a> in 1988.</p><h2 id="_2-customer-fdm-3d-printing" tabindex="-1">2. Customer FDM 3D printing <a class="header-anchor" href="#_2-customer-fdm-3d-printing" aria-label="Permalink to &quot;2. Customer FDM 3D printing&quot;">​</a></h2><p>It is very popular even somebody use FDM 3D printing replace all 3D printing. The reason of customer FDM 3D printing is following:</p><ul><li><p>Open source: FDM 3D printing is open source from 2005 in England. <a href="https://en.wikipedia.org/wiki/RepRap_project" target="_blank" rel="noreferrer">RepRap project(short for replicating rapid prototyper)</a> open source all <a href="https://reprap.org/wiki/Build_A_RepRap" target="_blank" rel="noreferrer">detail</a> according to <a href="https://en.wikipedia.org/wiki/GNU_General_Public_License" target="_blank" rel="noreferrer">GNU General Public License</a><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/First_replication.jpg" alt=""> (reference from <a href="./reprap.org/wiki/RepRap.html">RepRap</a>) it push forward the develop and popular in maker community. Because RepRap is humanity&#39;s first general-purpose <a href="https://en.wikipedia.org/wiki/Self-replicating_machine" target="_blank" rel="noreferrer">self-replicating manufacturing machine</a>. Makers can easy to build their own FDM 3D printing with the basic technology.</p></li><li><p>Easy operate:open source model,software setting, filament prepare, machine check and operation are easy to learn.</p><ul><li><p><a href="./www.makerbot.com.html">Makerbot</a> build <a href="http://thingiverse.com/" target="_blank" rel="noreferrer">Thingiverse</a> which is the biggest open source 3D printing model community in the world. Maker can download the model they need. It lows down the hardness in design. <img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/thingiverse.png" alt=""></p></li><li><p><a href="http://ultimaker.com" target="_blank" rel="noreferrer">Ultimaker</a> provide <a href="https://ultimaker.com/en/products/ultimaker-cura-software" target="_blank" rel="noreferrer">Cura</a> which is easy to set 3D printing parameter <img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/cura.png" alt=""></p></li><li><p><a href="https://bambulab.com/en" target="_blank" rel="noreferrer">Bambambulab </a>build <a href="https://makerworld.com/" target="_blank" rel="noreferrer">MakerWorld</a><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/WX20231114-211857@2x.png" alt=""></p></li><li><p>Filament prepare: We can load material according to the flowing pictures:<br><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/filament4.jpg" alt=""></p></li></ul></li><li><p>low cost :Because of &quot;Open Source&quot;, almost every component of customer FDM 3D printing is standard part and we can purchase them online (<a href="https://s.taobao.com/search?q=3d%E6%89%93%E5%8D%B0%E9%9B%B6%E4%BB%B6&amp;imgfile=&amp;js=1&amp;stats_click=search_radio_all%3A1&amp;initiative_id=staobaoz_20190401&amp;ie=utf8" target="_blank" rel="noreferrer">Taobao</a> for reference ). Maker and 3D printing company can design their own machine and then purchase most of components in market.</p></li></ul><p>Obviously, maker ,design for their prototype and maker education would use customer FDM 3D printing.</p><h2 id="_3-industry-fdm-3d-printing" tabindex="-1">3.Industry FDM 3D printing <a class="header-anchor" href="#_3-industry-fdm-3d-printing" aria-label="Permalink to &quot;3.Industry FDM 3D printing&quot;">​</a></h2><p>But industry need more. We can find some industry FDM 3D printing companys , for example</p><ul><li><a href="https://www.stratasys.com/fdm-technology" target="_blank" rel="noreferrer">Stratasys FDM </a> has many <a href="https://www.stratasys.com/materials/search?technologies=ff37d7b8297c4e43977c155d765f3305&amp;sortIndex=0" target="_blank" rel="noreferrer">industry materials(ABS, Nylon,TPU, Carbon Fiber……)</a> which can meet high strength and reliable industry requirement.</li></ul><p><img src="https://gitlab.com/picbed/bed/uploads/ddb48b0b3acfdd3770473b5e3f7f0cfd/stratasysFDM.png" alt=""></p><ul><li><p><a href="./www.desktopmetal.com.html">Desktop Metal</a>: Powered by Single Pass Jetting™ (SPJ™), the Production System features bi-directional printing where all steps of the print process—powder deposition, spreading, compacting, ballistic suppression, and binder jet printing—are applied with each pass over the build area. Whenever there is movement, there is printing—making it the fastest way to print complex metal parts. <img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/howitworks.jpg" alt=""></p></li><li><p><a href="./markforged.com.html">Markforged</a>: With Markforged 3D printers user can economically print with advanced materials including nylon, chopped carbon fiber, reinforced continuous fiber, and metal. <img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/3D-Parts-Unlimited-Markforged-Material-Relations.png" alt=""></p></li></ul><h2 id="_4-the-principle-of-fdm" tabindex="-1">4.The principle of FDM <a class="header-anchor" href="#_4-the-principle-of-fdm" aria-label="Permalink to &quot;4.The principle of FDM&quot;">​</a></h2><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/fdm.png" alt=""> There are 2 kinds of FDM 3D printing Cartesian(left one:Red): 3 motor control x,y,z axis and the machine is stable; Delta(Right one: Blue): The key design feature is the use of parallelograms in the arms, which maintains the orientation of the end effector which restrict the movement of the end platform to pure translation, i.e. only movement in the X, Y or Z direction. The advantage of delta is fast and cost is low. Basic principle :</p><ul><li>First step motor control drive wheel and push forward filament into machine&#39;s hot nozzle;</li><li>Hot nozzle heat filament and liquifier it. Then liquid mater drop down because of gravity.</li><li>3 motor control x,y,z distance;</li><li>Material drop down to certain position.</li><li>Build model one layer by one layer</li></ul><h2 id="_5-material" tabindex="-1">5. Material <a class="header-anchor" href="#_5-material" aria-label="Permalink to &quot;5. Material&quot;">​</a></h2><p>Obviously, ABS and PLA are most popular in FDM 3D printing. They have different features. For ABS, the mechanical properties is better than PLA and easy to post polish. But the model is easy to bend at the begging of printing. In addition when the machine in printing, ABS waste dust diffuse which is bad to body. So we will find most of FDM machine for ABS would enclose, need hot bed for platform. For PLA, the material is health to body and could connect with platform to avoid bending.But it is a little hard to post polish. In addition, we can provide many different kind of industry materials as following</p><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/10-thermo-pyramid.png" alt=""></p><p>reference from <a href="https://www.3dhubs.com/knowledge-base/introduction-fdm-3D-printing" target="_blank" rel="noreferrer">3D Hubs</a></p><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/FDM-material-datasheet-matrix2.png" alt=""></p><p>we can find the detail introduction in this <a href="https://filament2print.com/gb/blog/39_paek-filaments-3d-printing.html" target="_blank" rel="noreferrer">link</a> about how to do this test <img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/FDM-02.jpg" alt=""></p><h2 id="_6-application" tabindex="-1">6. Application <a class="header-anchor" href="#_6-application" aria-label="Permalink to &quot;6. Application&quot;">​</a></h2><h4 id="_6-1-education" tabindex="-1">6.1. Education <a class="header-anchor" href="#_6-1-education" aria-label="Permalink to &quot;6.1. Education&quot;">​</a></h4><p>3D printing especial FDM 3D printing is one of the tool for <a href="http://www.stemedcoalition.org/" target="_blank" rel="noreferrer">STEM education</a> and <a href="http://www.makereducation.com/" target="_blank" rel="noreferrer">maker education</a>. With the tool of 3D printing, Students can learn, design, make, test their structure quickly to verify their concept. In addition, FDM 3D printing is one of the efficient method to make the prototype.</p><h4 id="_6-2-maker-project" tabindex="-1">6.2. Maker project <a class="header-anchor" href="#_6-2-maker-project" aria-label="Permalink to &quot;6.2. Maker project&quot;">​</a></h4><p>For maker project, they want to process quick and low cost. Before the popular of FDM 3D printing, hand working( but can&#39;t make sure the precision and cost time) or Industrial processing(the cost is high ) can support maker&#39;s project, obviously it&#39;s not good choice. <img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/1.jpg" alt=""> RepRap project is maker project. Because of the gene, I think FDM 3D printing born for maker. Maker can design their own structure and then print it in machine high efficient and low cost. Then maker can assemble and test in their own project. Some makers even can use FDM model in small batch product and we can find many in <a href="https://www.kickstarter.com/" target="_blank" rel="noreferrer">Kickstart</a>.<br> Now some FDM 3D printing even can print industry material for function part such as : Nylon,PEEK, Carbon fiber,TPU.</p><h4 id="_6-3-prototype-test" tabindex="-1">6.3. Prototype test <a class="header-anchor" href="#_6-3-prototype-test" aria-label="Permalink to &quot;6.3. Prototype test&quot;">​</a></h4><p>The price of CNC and other 3D printing is very high, in addition they need experience worker to run the machine. So most of company would send their design to vendor to process, but it need time.<br> In industry, FDM 3D printing is good choice for designer&#39;s prototype test. Company could purchase one then test their design by themselves. If there is any problem, they can redesign and make it again. For make it can save many time . <img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/fdmdemo.png" alt=""></p><h4 id="_6-4-custom-product-industry-useage" tabindex="-1">6.4. Custom product/industry useage <a class="header-anchor" href="#_6-4-custom-product-industry-useage" aria-label="Permalink to &quot;6.4. Custom product/industry useage&quot;">​</a></h4><p>For some designer ,artist, they want to design unique product. Some of them would use 3D printing to custom some detail.</p><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/fdmindustry2.png" alt=""></p>',31)])])}const u=t(o,[["render",n]]);export{m as __pageData,u as default};
